script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;
  &VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&VoucherLogHandleStatus;if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d86')._controlBehavior;
  switch (action) {
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Save':
      var o = f.getItem('mau_bc'), v = ($func.trim(o.value) == '');
      f.getItem('ma_tc').field.AllowNulls = v;
      f.getItem('ma_thue').field.AllowNulls = v;
      f.getItem('tk_thue').field.AllowNulls = v;
      f.getItem('ma_kh2').field.AllowNulls = (v || (f.getItemValue('tk_cn') == 0));
      o.field.AllowNulls = true;
      if (v && ($func.trim(f.getItemValue('ma_tc')) + $func.trim(f.getItemValue('ma_thue')) + $func.trim(f.getItemValue('tk_thue')) + $func.trim(f.getItemValue('ma_kh2')) != '')) o.field.AllowNulls = false;
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
    &CancelStatusExplore;&VoucherLogHandleStatusExplore;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d86')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt, t_thue_nt, t_tt_nt:t_tien, t_thue, t_tt');
    v.addGridFields(g, 'gia_nt, tien_nt:gia, tien');
    v.addTotalFields(g, [['t_tien_nt', 'tien_nt'], ['t_tien', 'tien']]);
    v.set_referenceFields(null);
    v.set_executeExpression(['[t_thue_nt]:=[t_tien_nt]*[thue_suat]/100', '[t_thue]:=[t_tien]*[thue_suat]/100', '[t_tt_nt]:=[t_tien_nt]+[t_thue_nt]', '[t_tt]:=[t_tien]+[t_thue]']);
    &CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    var f = sender.get_element().parentForm;
    if (e.object._baseCurrency == e.type) {
      var a = [['d86', 't_thue_nt'], 'mau_bc', 'so_ct_goc'];
      focus$Voucher$Tab(f, a);
      &PostCurrencySelected;
    }
  }
}



function onChange$Voucher$Tab(sender, e) {
  var a = ['d86', 'mau_bc', 'so_ct_goc'];
  focus$Voucher$Tab(sender.parentForm, a);
  &PostTabFocus;
}
function focus$Voucher$Tab(f, a) {
  if (f._usedEI) Array.add(a, 'sd_hddt_yn');
  &ListTabChange;&PostTabChange;
  f.focusWhenTabChanged(a);
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd'], o);}
function onChange$Voucher$Reason(o) {o.parentForm.request('Reason', 'Reason', ['ma_nx'], o);}
function onChange$Voucher$TaxCode(o) {
  var f = o.parentForm, c = 'TaxCode';
  if (!$func.trim(o.value)) f.raiseResponseComplete(new FastBusiness.AjaxControlExtender.EventArgs(f, {Context: c, Result: [0, '', '', 0]}));
    else f.request(c, c, ['ma_thue'], o);
}
function onChange$Voucher$TaxAccount(o) {o.parentForm.request('TaxAccount', 'TaxAccount', ['tk_thue'], o);}
function onChange$Voucher$ForeignCurrencyTaxAmount(o) {
    var f = o.parentForm;
    f.executeExpression(['[t_thue]:=[t_thue_nt]*[ty_gia]', '[t_tt_nt]:=[t_tien_nt]+[t_thue_nt]', '[t_tt]:=[t_tien]+[t_thue]']);
    f.live(f.getItem('t_thue'));
}
function onChange$Voucher$BaseCurrencyTaxAmount(o) {o.parentForm.executeExpression(['[t_tt]:=[t_tien]+[t_thue]']);}
/* </flatten> */


function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      set$Voucher$DefaultValue(f);
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      set$Voucher$DefaultValue(f);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;
      &ListResponseTicket;

    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ong_ba', result[2].Value, null, true);
      &EICustomerResponseComplete;
      f.live(f.getItem('ong_ba'));
      break;
    case 'Reason':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, false);
      f.live(f.getItem('tk'));
      break;
    case 'TaxCode':
      var r = result[0].Value;
      if (f.getItemValue('thue_suat') != r) {
        f.setItemValue('thue_suat', r);
        f.executeExpression(['[t_thue_nt]:=[t_tien_nt]*[thue_suat]/100', '[t_thue]:=[t_tien]*[thue_suat]/100', '[t_tt_nt]:=[t_tien_nt]+[t_thue_nt]', '[t_tt]:=[t_tien]+[t_thue]']);
      }
      f.setItemControlBehavior('tk_thue', result[1].Value, result[2].Value, true);
      f.setItemValue('tk_cn', result[3].Value);
      f.live(f.getItem('tk_thue'));
      break;
    case 'TaxAccount':
      f.setItemValue('tk_cn', result[0].Value);
      break;
    case 'Transaction':
      f.setItemValue('loai_ct', result[0].Value);
      break;
      &EIResponseCompleteChecking;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function set$Voucher$DefaultValue(f) {
  if (f._action != 'New') return;
  if ($func.trim(f.getItemValue('ma_thue')) == '' && f._defaultTaxCode) {
    f.setItemValue('ma_thue', f._defaultTaxCode);
    f.setItemValue('ma_tc', f._defaultTaxProperty);
    f.setItemValue('thue_suat', f._defaultTaxRate);
    f.setItemValue('tk_thue', f._defaultTaxAccount);
    f.setItemValue('tk_cn', f._defaultTaxType);
    f.getItem('ten_bc%l').value = f._reportFormName;
    f.getItem('ten_tc%l').value = f._taxPropertyName;
    f.getItem('ten_tk_thue%l').value = f._taxAccountName;
    f.getItem('ten_thue%l').value = f._taxCodeName;
  }
}
function when$VoucherCopying(f) {f.setItemValue('stt_rec', '');}
/* </flatten> */
      &ListScript;
      &PostScript;
